  transition: border-color 0.2s;
}
.search-box__input:focus { border-color: var(--charcoal); }
.search-box__input::placeholder { color: var(--charcoal-light); }
.search-box__icon {
  position: absolute; right: 0.75rem; top: 50%; transform: translateY(-50%);
  color: var(--charcoal-light); pointer-events: none;
}

/* ─── CATEGORY FILTER ─── */
.category-filter {
  display: flex; gap: 0.75rem; flex-wrap: wrap; margin-bottom: 3rem;
}
.category-filter__btn {
  padding: 0.45rem 1.2rem;
  font-family: var(--font-body); font-size: 0.7rem; font-weight: 400;
  letter-spacing: 0.12em; text-transform: uppercase;
  border: 1.5px solid var(--border); color: var(--charcoal-light);
  transition: var(--transition);
}
.category-filter__btn:hover,
.category-filter__btn--active {
  background: var(--charcoal); color: var(--cream);
  border-color: var(--charcoal);
}

/* ─── PRODUCT GRID ─── */
.product-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 2rem;
}
.product-card {
  background: var(--white); cursor: pointer;
  transition: var(--transition);
  animation: fadeUp 0.5s ease both;
}
.product-card:hover { transform: translateY(-4px); box-shadow: var(--shadow-md); }
.product-card__image {
  position: relative; overflow: hidden;
  aspect-ratio: 3/4; background: var(--cream-dark);
}
.product-card__image img {
  width: 100%; height: 100%; object-fit: cover;
  transition: transform 0.5s ease;
}
.product-card:hover .product-card__image img { transform: scale(1.05); }
.product-card__placeholder {
  width: 100%; height: 100%;
  display: flex; align-items: center; justify-content: center;
  font-family: var(--font-display); font-size: 2rem;
  font-weight: 300; color: rgba(28,26,24,0.2);
  background: linear-gradient(135deg, var(--cream-dark), #e0d8cc);
}
.product-card__badge {
  position: absolute; top: 1rem; left: 1rem;
  background: var(--terracotta); color: var(--white);
  font-size: 0.6rem; font-weight: 500; letter-spacing: 0.1em;
  text-transform: uppercase; padding: 0.3rem 0.7rem;
}
.product-card__badge--out { background: var(--charcoal-light); }
.product-card__body { padding: 1.25rem 1rem; }
.product-card__cat {
  font-size: 0.6rem; letter-spacing: 0.2em; text-transform: uppercase;
  color: var(--terracotta); margin-bottom: 0.4rem;
}
.product-card__name {
  font-family: var(--font-display); font-size: 1.15rem;
  font-weight: 400; color: var(--charcoal);
  line-height: 1.3; margin-bottom: 0.75rem;
}
.product-card__footer {
  display: flex; align-items: center; justify-content: space-between;
}
.product-card__price {
  font-family: var(--font-display); font-size: 1.1rem; font-weight: 600; color: var(--charcoal);
}
.product-card__add {
  width: 36px; height: 36px; border: 1.5px solid var(--charcoal);
  display: flex; align-items: center; justify-content: center;
  font-size: 1.2rem; color: var(--charcoal); transition: var(--transition);
}
.product-card__add:hover { background: var(--charcoal); color: var(--cream); }
.product-card__add:disabled { border-color: var(--border); color: var(--charcoal-light); cursor: not-allowed; }

/* ─── STATES ─── */
.loading-state {
  grid-column: 1/-1;
  display: flex; flex-direction: column; align-items: center;
  gap: 1rem; padding: 5rem 0; color: var(--charcoal-light);
}
.spinner {
  width: 32px; height: 32px; border: 2px solid var(--border);
  border-top-color: var(--charcoal); border-radius: 50%;
  animation: spin 0.7s linear infinite;
}
.empty-state { grid-column: 1/-1; text-align: center; padding: 5rem 0; color: var(--charcoal-light); }
.empty-state p { font-family: var(--font-display); font-size: 1.4rem; font-weight: 300; }

/* ─── CART SIDEBAR ─── */
.cart-sidebar {
  position: fixed; top: 0; right: 0; bottom: 0; width: 380px; z-index: 160;
  background: var(--white); display: flex; flex-direction: column;
  transform: translateX(100%); transition: var(--transition); box-shadow: var(--shadow-lg);
}
.cart-sidebar.open { transform: translateX(0); }
.cart-sidebar__header {
  display: flex; align-items: center; justify-content: space-between;
  padding: 1.5rem 1.75rem; border-bottom: 1px solid var(--border);
}
.cart-sidebar__title {
  font-family: var(--font-display); font-size: 1.5rem; font-weight: 400;
}
.cart-sidebar__close { font-size: 1rem; color: var(--charcoal-light); padding: 4px 8px; }
.cart-sidebar__items { flex: 1; overflow-y: auto; padding: 1.5rem 1.75rem; }
.cart-empty {
  display: flex; flex-direction: column; align-items: center; gap: 1rem;
  padding: 4rem 0; color: var(--charcoal-light);
  font-family: var(--font-display); font-size: 1rem;
}
.cart-item {
  display: flex; gap: 1rem; padding: 1.25rem 0;
  border-bottom: 1px solid var(--border);
  animation: fadeUp 0.3s ease;
}
.cart-item__img {
  width: 70px; height: 90px; object-fit: cover;
  background: var(--cream-dark); flex-shrink: 0;
}
.cart-item__img-placeholder {
  width: 70px; height: 90px;
  background: linear-gradient(135deg, var(--cream-dark), #e0d8cc);
  display: flex; align-items: center; justify-content: center;
  font-family: var(--font-display); font-size: 1.2rem; color: rgba(28,26,24,0.25);
  flex-shrink: 0;
}
.cart-item__info { flex: 1; min-width: 0; }
.cart-item__name {
  font-family: var(--font-display); font-size: 1rem; font-weight: 400;
  line-height: 1.3; margin-bottom: 0.3rem;
  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
}
.cart-item__price { font-size: 0.85rem; color: var(--charcoal-light); margin-bottom: 0.75rem; }
.cart-item__controls { display: flex; align-items: center; gap: 0.5rem; }
.cart-item__qty-btn {
  width: 26px; height: 26px; border: 1px solid var(--border);
  font-size: 0.9rem; color: var(--charcoal);
  display: flex; align-items: center; justify-content: center; transition: var(--transition);
}
.cart-item__qty-btn:hover { background: var(--charcoal); color: var(--cream); }
.cart-item__qty { font-size: 0.85rem; min-width: 20px; text-align: center; }
.cart-item__remove { margin-left: auto; font-size: 0.75rem; color: var(--charcoal-light); }
.cart-item__remove:hover { color: var(--terracotta); }
.cart-sidebar__footer { padding: 1.5rem 1.75rem; border-top: 1px solid var(--border); }
.cart-sidebar__total {
  display: flex; justify-content: space-between; align-items: center;
  margin-bottom: 1.25rem;
  font-family: var(--font-display); font-size: 1.15rem;
}

/* ─── CHECKOUT MODAL ─── */
.modal {
  position: fixed; inset: 0; z-index: 250;
  display: flex; align-items: center; justify-content: center; padding: 1rem;
  pointer-events: none; opacity: 0; transition: opacity 0.3s;
}
.modal.open { pointer-events: all; opacity: 1; }
.modal__panel {
  background: var(--white); width: 100%; max-width: 580px;
  max-height: 90vh; overflow-y: auto;
  transform: translateY(20px); transition: transform 0.35s ease;
  position: relative; z-index: 1;
}
.modal.open .modal__panel { transform: translateY(0); }
.modal__panel--small { max-width: 420px; }
.modal__header {
  display: flex; align-items: center; justify-content: space-between;
  padding: 1.75rem 2rem 1.25rem; border-bottom: 1px solid var(--border);
  position: sticky; top: 0; background: var(--white); z-index: 1;
}
.modal__title { font-family: var(--font-display); font-size: 1.5rem; font-weight: 400; }
.modal__close { font-size: 1rem; color: var(--charcoal-light); padding: 4px 8px; }

/* ─── FORM ─── */
.checkout-form { padding: 2rem; display: flex; flex-direction: column; gap: 1.25rem; }
.form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; }
.form-group { display: flex; flex-direction: column; gap: 0.4rem; }
.form-label {
  font-size: 0.7rem; letter-spacing: 0.15em; text-transform: uppercase;
  color: var(--charcoal-light); font-weight: 400;
}
.required { color: var(--terracotta); }
.form-input {
  background: var(--cream); border: 1.5px solid transparent;
  padding: 0.75rem 1rem;
  font-family: var(--font-body); font-size: 0.9rem; color: var(--charcoal);
  outline: none; transition: border-color 0.2s; width: 100%;
}
.form-input:focus { border-color: var(--charcoal); background: var(--white); }
.form-input.error { border-color: var(--terracotta); }
.form-textarea { resize: vertical; min-height: 80px; }
.form-error { font-size: 0.75rem; color: var(--terracotta); min-height: 1em; }
.form-error-global { font-size: 0.85rem; color: var(--terracotta); text-align: center; min-height: 1em; }

/* ─── ORDER SUMMARY ─── */
.order-summary { background: var(--cream); padding: 1.25rem; }
.order-summary__title {
  font-family: var(--font-display); font-size: 1rem; font-weight: 400;
  margin-bottom: 0.75rem; letter-spacing: 0.05em;
}
.order-summary__item {
  display: flex; justify-content: space-between;
  font-size: 0.85rem; padding: 0.3rem 0; color: var(--charcoal-mid);
}
.order-summary__total {
  display: flex; justify-content: space-between;
  padding-top: 0.75rem; margin-top: 0.75rem;
  border-top: 1px solid var(--border);
  font-family: var(--font-display); font-size: 1.1rem;
}

/* ─── SUCCESS ─── */
.success-state {
  padding: 3.5rem 2rem;
  display: flex; flex-direction: column; align-items: center; gap: 1rem; text-align: center;
}
.success-state__icon {
  width: 60px; height: 60px; border-radius: 50%;
  background: var(--charcoal); color: var(--cream);
  font-size: 1.5rem; display: flex; align-items: center; justify-content: center;
}
.success-state__title { font-family: var(--font-display); font-size: 1.75rem; font-weight: 400; }
.success-state__msg { color: var(--charcoal-light); line-height: 1.7; }

/* ─── FOOTER ─── */
.footer { background: var(--charcoal); color: var(--cream); margin-top: 4rem; }
.footer__inner {
  display: grid; grid-template-columns: 1.5fr 1fr 1fr;
  gap: 3rem; padding: 4rem 2rem 3rem; max-width: 1400px; margin: 0 auto;
}
.footer__logo {
  font-family: var(--font-display); font-size: 2rem; font-weight: 600;
  letter-spacing: 0.15em; margin-bottom: 0.75rem;
}
.footer__tagline { color: rgba(247,242,236,0.45); font-size: 0.85rem; font-style: italic; }
.footer h4 {
  font-family: var(--font-body); font-size: 0.65rem; font-weight: 500;
  letter-spacing: 0.25em; text-transform: uppercase;
  color: rgba(247,242,236,0.45); margin-bottom: 1.25rem;
}
.footer__links ul { display: flex; flex-direction: column; gap: 0.6rem; }
.footer__links a {
  font-family: var(--font-display); font-size: 1rem;
  color: rgba(247,242,236,0.75); transition: color 0.2s;
}
.footer__links a:hover { color: var(--gold); }
.footer__contact p { font-size: 0.85rem; color: rgba(247,242,236,0.65); margin-bottom: 0.35rem; }
.footer__bottom {
  border-top: 1px solid rgba(247,242,236,0.1);
  padding: 1.25rem 2rem; text-align: center;
  font-size: 0.75rem; color: rgba(247,242,236,0.3);
}

/* ─── ANIMATIONS ─── */
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(24px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes fadeIn {
  from { opacity: 0; } to { opacity: 1; }
}
@keyframes spin {
  to { transform: rotate(360deg); }
}
@keyframes scrollLine {
  0% { left: -100%; } 100% { left: 100%; }
}

.product-card:nth-child(1) { animation-delay: 0.05s; }
.product-card:nth-child(2) { animation-delay: 0.1s; }
.product-card:nth-child(3) { animation-delay: 0.15s; }
.product-card:nth-child(4) { animation-delay: 0.2s; }
.product-card:nth-child(5) { animation-delay: 0.25s; }
.product-card:nth-child(6) { animation-delay: 0.3s; }
.product-card:nth-child(7) { animation-delay: 0.35s; }
.product-card:nth-child(8) { animation-delay: 0.4s; }

/* ─── RESPONSIVE ─── */
@media (max-width: 768px) {
  .hero__title { font-size: 3rem; }
  .shop { padding: 4rem 1.25rem 3rem; }
  .shop__header { flex-direction: column; align-items: flex-start; }
  .product-grid { grid-template-columns: repeat(2, 1fr); gap: 1rem; }
  .cart-sidebar { width: 100%; }
  .footer__inner { grid-template-columns: 1fr; gap: 2rem; }
  .form-row { grid-template-columns: 1fr; }
  .modal__panel { max-height: 95vh; }
}
@media (max-width: 480px) {
  .product-grid { grid-template-columns: 1fr; }
  .hero__title { font-size: 2.5rem; }
}
