/**
 * MAISON — Fashion Store App
 */

// ── State ──────────────────────────────────────
let cart = JSON.parse(localStorage.getItem('maison_cart') || '[]');
let allProducts = [];
let currentCategory = null;
let searchTimeout = null;

// ── Helpers ────────────────────────────────────
function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function formatPrice(num) {
  return Number(num).toLocaleString('vi-VN') + ' ₫';
}

function saveCart() {
  localStorage.setItem('maison_cart', JSON.stringify(cart));
}

// ── Cart logic ────────────────────────────────
function getCartTotal() {
  return cart.reduce((sum, item) => sum + item.price * item.qty, 0);
}

function updateCartCount() {
  const total = cart.reduce((sum, item) => sum + item.qty, 0);
  const el = document.getElementById('cartCount');
  el.textContent = total;
  el.classList.toggle('visible', total > 0);
}

function addToCart(product) {
  const existing = cart.find(i => i.id === product.id);
  if (existing) {
    existing.qty = Math.min(existing.qty + 1, product.stock);
  } else {
    cart.push({ id: product.id, name: product.name, price: Number(product.price), image_url: product.image_url, stock: product.stock, qty: 1 });
  }
  saveCart();
  updateCartCount();
  renderCartItems();
  openCart();
}

function removeFromCart(id) {
  cart = cart.filter(i => i.id !== id);
  saveCart();
  updateCartCount();
  renderCartItems();
}

function changeQty(id, delta) {
  const item = cart.find(i => i.id === id);
  if (!item) return;
  item.qty = Math.max(1, Math.min(item.qty + delta, item.stock));
  saveCart();
  updateCartCount();
  renderCartItems();
}

function renderCartItems() {
  const container = document.getElementById('cartItems');
  const footer = document.getElementById('cartFooter');
  const emptyEl = document.getElementById('cartEmpty');

  if (cart.length === 0) {
    container.innerHTML = '';
    container.appendChild(emptyEl);
    emptyEl.style.display = 'flex';
    footer.style.display = 'none';
    return;
  }

  emptyEl.style.display = 'none';
  footer.style.display = 'block';

  container.innerHTML = cart.map(item => `
    <div class="cart-item">
      ${item.image_url
        ? `<img class="cart-item__img" src="${escapeHtml(item.image_url)}" alt="${escapeHtml(item.name)}" onerror="this.style.display='none'">`
        : `<div class="cart-item__img-placeholder">${escapeHtml(item.name[0])}</div>`
      }
      <div class="cart-item__info">
        <div class="cart-item__name">${escapeHtml(item.name)}</div>
        <div class="cart-item__price">${formatPrice(item.price)}</div>
        <div class="cart-item__controls">
          <button class="cart-item__qty-btn" onclick="changeQty(${item.id}, -1)">−</button>
          <span class="cart-item__qty">${item.qty}</span>
          <button class="cart-item__qty-btn" onclick="changeQty(${item.id}, 1)">+</button>
          <button class="cart-item__remove" onclick="removeFromCart(${item.id})">Xóa</button>
        </div>
      </div>
    </div>
  `).join('');

  document.getElementById('cartTotal').textContent = formatPrice(getCartTotal());
}

// ── Cart UI ───────────────────────────────────
function openCart() {
  document.getElementById('cartSidebar').classList.add('open');
  document.getElementById('cartOverlay').classList.add('visible');
  document.body.style.overflow = 'hidden';
}

function closeCart() {
  document.getElementById('cartSidebar').classList.remove('open');
  document.getElementById('cartOverlay').classList.remove('visible');
  document.body.style.overflow = '';
}

// ── Products ──────────────────────────────────
async function loadCategories() {
  try {
    const cats = await api.get('/api/products/categories');
    renderCategoryFilter(cats);
    renderFooterCats(cats);
    renderMobileNav(cats);
  } catch (e) {
    console.error('Failed to load categories', e);
  }
}

function renderCategoryFilter(cats) {
  const container = document.getElementById('categoryFilter');
  const allBtn = container.querySelector('[data-cat=""]');

  cats.forEach(cat => {
    const btn = document.createElement('button');
    btn.className = 'category-filter__btn';
    btn.dataset.cat = cat;
    btn.textContent = cat;
    btn.onclick = () => filterCategory(cat);
    container.appendChild(btn);
  });
}

function renderFooterCats(cats) {
  const ul = document.getElementById('footerCats');
  ul.innerHTML = cats.map(cat =>
    `<li><a href="#" onclick="filterCategory('${escapeHtml(cat)}'); return false;">${escapeHtml(cat)}</a></li>`
  ).join('');
}

function renderMobileNav(cats) {
  const list = document.getElementById('mobileNavList');
  cats.forEach(cat => {
    const li = document.createElement('li');
    li.innerHTML = `<a href="#" onclick="filterCategory('${escapeHtml(cat)}'); closeMobileNav(); return false;">${escapeHtml(cat)}</a>`;
    list.appendChild(li);
  });
}

async function loadProducts(category = null, search = null) {
  const grid = document.getElementById('productGrid');
  grid.innerHTML = `<div class="loading-state"><div class="spinner"></div><p>Đang tải sản phẩm...</p></div>`;

  try {
    const params = {};
    if (category) params.category = category;
    if (search) params.search = search;
    allProducts = await api.get('/api/products', params);
    renderProducts(allProducts);
  } catch (e) {
    grid.innerHTML = `<div class="empty-state"><p>Không thể tải sản phẩm. Vui lòng thử lại.</p></div>`;
  }
}

function renderProducts(products) {
  const grid = document.getElementById('productGrid');

  if (products.length === 0) {
    grid.innerHTML = `<div class="empty-state"><p>Không tìm thấy sản phẩm nào.</p></div>`;
    return;
  }

  grid.innerHTML = products.map((p, i) => {
    const outOfStock = p.stock === 0;
    const imageContent = p.image_url
      ? `<img src="${escapeHtml(p.image_url)}" alt="${escapeHtml(p.name)}" loading="lazy" onerror="this.parentElement.innerHTML='<div class=\\"product-card__placeholder\\">${escapeHtml(p.name[0])}</div>'">`
      : `<div class="product-card__placeholder">${escapeHtml(p.name[0])}</div>`;

    return `
      <div class="product-card" style="animation-delay:${i * 0.05}s">
        <div class="product-card__image">
          ${imageContent}
          ${outOfStock ? '<span class="product-card__badge product-card__badge--out">Hết hàng</span>' : '<span class="product-card__badge">Mới</span>'}
        </div>
        <div class="product-card__body">
          ${p.category ? `<p class="product-card__cat">${escapeHtml(p.category)}</p>` : ''}
          <h3 class="product-card__name">${escapeHtml(p.name)}</h3>
          <div class="product-card__footer">
            <span class="product-card__price">${formatPrice(p.price)}</span>
            <button class="product-card__add" ${outOfStock ? 'disabled' : ''} onclick='addToCart(${JSON.stringify({id:p.id, name:p.name, price:Number(p.price), image_url:p.image_url, stock:p.stock})})' title="Thêm vào giỏ">+</button>
          </div>
        </div>
      </div>
    `;
  }).join('');
}

function filterCategory(cat) {
  currentCategory = cat;

  // Update filter buttons
  document.querySelectorAll('.category-filter__btn').forEach(btn => {
    btn.classList.toggle('category-filter__btn--active', btn.dataset.cat === (cat || ''));
  });

  loadProducts(cat, document.getElementById('searchInput').value.trim() || null);
}

function handleSearch() {
  clearTimeout(searchTimeout);
  searchTimeout = setTimeout(() => {
    const q = document.getElementById('searchInput').value.trim();
    loadProducts(currentCategory, q || null);
  }, 400);
}

function scrollToShop() {
  document.getElementById('shopSection').scrollIntoView({ behavior: 'smooth' });
}

// ── Mobile Nav ────────────────────────────────
function openMobileNav() {
  document.getElementById('mobileNav').classList.add('open');
  document.getElementById('navOverlay').classList.add('visible');
  document.body.style.overflow = 'hidden';
}

function closeMobileNav() {
  document.getElementById('mobileNav').classList.remove('open');
  document.getElementById('navOverlay').classList.remove('visible');
  document.body.style.overflow = '';
}

// ── Checkout ──────────────────────────────────
function openCheckout() {
  closeCart();
  renderOrderSummary();
  document.getElementById('checkoutModal').classList.add('open');
  document.getElementById('modalOverlay').classList.add('visible');
  document.body.style.overflow = 'hidden';
}

function closeCheckout() {
  document.getElementById('checkoutModal').classList.remove('open');
  document.getElementById('modalOverlay').classList.remove('visible');
  document.body.style.overflow = '';
}

function renderOrderSummary() {
  const container = document.getElementById('orderSummaryItems');
  container.innerHTML = cart.map(item => `
    <div class="order-summary__item">
      <span>${escapeHtml(item.name)} × ${item.qty}</span>
      <span>${formatPrice(item.price * item.qty)}</span>
    </div>
  `).join('');
  document.getElementById('orderTotal').textContent = formatPrice(getCartTotal());
}

function closeSuccess() {
  document.getElementById('successModal').classList.remove('open');
  document.getElementById('successOverlay').classList.remove('visible');
  document.body.style.overflow = '';
}

// ── Header scroll ─────────────────────────────
window.addEventListener('scroll', () => {
  document.getElementById('header').classList.toggle('header--scrolled', window.scrollY > 20);
});

// ── Form submission ───────────────────────────
document.getElementById('checkoutForm').addEventListener('submit', async (e) => {
  e.preventDefault();

  const name = document.getElementById('custName').value.trim();
  const email = document.getElementById('custEmail').value.trim();
  const phone = document.getElementById('custPhone').value.trim();
  const address = document.getElementById('custAddress').value.trim();

  // Clear errors
  ['custName', 'custEmail', 'custAddress'].forEach(id => {
    document.getElementById(id).classList.remove('error');
  });
  document.getElementById('errName').textContent = '';
  document.getElementById('errEmail').textContent = '';
  document.getElementById('errAddress').textContent = '';
  document.getElementById('checkoutError').textContent = '';

  let valid = true;
  if (!name) {
    document.getElementById('custName').classList.add('error');
    document.getElementById('errName').textContent = 'Vui lòng nhập họ tên';
    valid = false;
  }
  if (!email || !/^[^@]+@[^@]+\.[^@]+$/.test(email)) {
    document.getElementById('custEmail').classList.add('error');
    document.getElementById('errEmail').textContent = 'Email không hợp lệ';
    valid = false;
  }
  if (!address) {
    document.getElementById('custAddress').classList.add('error');
    document.getElementById('errAddress').textContent = 'Vui lòng nhập địa chỉ';
    valid = false;
  }
  if (!valid) return;

  const submitBtn = document.getElementById('submitOrder');
  const submitText = document.getElementById('submitText');
  const spinner = document.getElementById('submitSpinner');
  submitBtn.disabled = true;
  submitText.style.display = 'none';
  spinner.style.display = 'block';

  try {
    await api.post('/api/orders', {
      customer_name: name,
      customer_email: email,
      customer_phone: phone || null,
      address,
      items: cart.map(i => ({ product_id: i.id, quantity: i.qty, price: i.price })),
    });

    closeCheckout();
    cart = [];
    saveCart();
    updateCartCount();
    renderCartItems();
    document.getElementById('checkoutForm').reset();

    // Show success
    document.getElementById('successModal').classList.add('open');
    document.getElementById('successOverlay').classList.add('visible');
    document.body.style.overflow = 'hidden';

    // Reload products to reflect updated stock
    loadProducts(currentCategory);

  } catch (err) {
    document.getElementById('checkoutError').textContent = err.message || 'Đặt hàng thất bại, vui lòng thử lại.';
  } finally {
    submitBtn.disabled = false;
    submitText.style.display = 'block';
    spinner.style.display = 'none';
  }
});

// ── Event listeners ───────────────────────────
